<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Desktop</title>
<style>
*{box-sizing:border-box;margin:0;padding:0}
body,html{width:100%;height:100%;overflow:hidden;font-family:'Segoe UI',Ubuntu,sans-serif}

#desktop{
  width:100vw;height:100vh;
  background:linear-gradient(135deg,#1a1a2e 0%,#16213e 35%,#0f3460 65%,#533483 100%);
  position:relative;overflow:hidden
}

/* Top bar */
#topbar{
  position:absolute;top:0;left:0;right:0;height:28px;
  background:rgba(15,15,15,0.88);backdrop-filter:blur(10px);
  display:flex;align-items:center;padding:0 16px;
  color:#ddd;font-size:13px;z-index:200;
  border-bottom:1px solid rgba(255,255,255,0.06)
}
#topbar-activities{font-weight:600;cursor:pointer}
#topbar-activities:hover{color:#fff}
#topbar-right{margin-left:auto;display:flex;gap:14px;align-items:center}
#clock{font-size:13px}

/* Taskbar */
#taskbar{
  position:absolute;bottom:0;left:50%;transform:translateX(-50%);
  height:58px;
  background:rgba(22,22,22,0.92);backdrop-filter:blur(14px);
  border-radius:16px 16px 0 0;
  display:flex;align-items:center;padding:0 14px;gap:10px;
  border:1px solid rgba(255,255,255,0.1);border-bottom:none;
  z-index:200
}
#taskbar button{
  width:46px;height:46px;border:none;border-radius:13px;
  background:rgba(255,255,255,0.08);color:#fff;font-size:22px;
  cursor:pointer;transition:background 0.15s,transform 0.12s;
  display:flex;align-items:center;justify-content:center;position:relative
}
#taskbar button:hover{background:rgba(255,255,255,0.18);transform:translateY(-5px) scale(1.12)}
#taskbar button::after{
  content:attr(data-tip);position:absolute;bottom:54px;
  background:rgba(0,0,0,0.82);color:#fff;font-size:11px;
  padding:3px 9px;border-radius:5px;white-space:nowrap;
  opacity:0;pointer-events:none;transition:opacity 0.18s;border:1px solid rgba(255,255,255,0.1)
}
#taskbar button:hover::after{opacity:1}

/* Window */
.window{
  position:absolute;background:#2d2d2d;border-radius:10px;
  box-shadow:0 24px 64px rgba(0,0,0,0.65),0 0 0 1px rgba(255,255,255,0.07);
  display:none;flex-direction:column;overflow:hidden;
  min-width:360px;min-height:240px
}
.window.visible{display:flex}

.win-titlebar{
  height:36px;background:#3a3a3a;display:flex;align-items:center;
  padding:0 10px;cursor:move;user-select:none;flex-shrink:0;
  border-bottom:1px solid rgba(0,0,0,0.35)
}
.win-controls{display:flex;gap:7px;align-items:center}
.win-btn{
  width:14px;height:14px;border-radius:50%;border:none;cursor:pointer;
  transition:filter 0.15s,opacity 0.15s;flex-shrink:0
}
.win-btn:hover{filter:brightness(1.25)}
.win-close{background:#ff5f57}
.win-minimize{background:#ffbd2e}
.win-maximize{background:#28c840}
.win-title{
  flex:1;color:#ddd;font-size:13px;font-weight:500;
  text-align:center;pointer-events:none;padding-right:55px
}

/* Files */
#files-window{top:80px;left:70px;width:560px;height:420px}

.files-toolbar{
  display:flex;align-items:center;padding:5px 10px;gap:8px;
  background:#363636;border-bottom:1px solid rgba(0,0,0,0.25);flex-shrink:0
}
#files-up{
  background:rgba(255,255,255,0.09);border:none;color:#ccc;
  border-radius:6px;padding:4px 12px;cursor:pointer;font-size:13px;
  transition:background 0.15s;white-space:nowrap
}
#files-up:hover{background:rgba(255,255,255,0.18)}
#files-path{
  flex:1;background:rgba(0,0,0,0.28);color:#e0e0e0;
  border-radius:6px;padding:4px 10px;font-size:13px;font-family:monospace;
  border:1px solid rgba(255,255,255,0.07);overflow:hidden;text-overflow:ellipsis;white-space:nowrap
}

#files-content{
  flex:1;overflow-y:auto;padding:10px;
  display:flex;flex-wrap:wrap;align-content:flex-start;gap:4px
}
#files-content::-webkit-scrollbar{width:6px}
#files-content::-webkit-scrollbar-track{background:transparent}
#files-content::-webkit-scrollbar-thumb{background:rgba(255,255,255,0.18);border-radius:3px}

.fs-item{
  width:90px;padding:8px 4px 6px;border-radius:8px;
  display:flex;flex-direction:column;align-items:center;
  cursor:pointer;transition:background 0.12s;
  color:#ddd;font-size:11px;text-align:center;
  word-break:break-all;user-select:none
}
.fs-item:hover{background:rgba(255,255,255,0.09)}
.fs-item.selected{background:rgba(230,115,20,0.28);outline:1px solid rgba(230,115,20,0.5)}
.fs-icon{font-size:30px;margin-bottom:4px;line-height:1;pointer-events:none}
.fs-label{pointer-events:none;line-height:1.3;max-width:82px;overflow:hidden;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical}

/* Notepad */
#notepad-window{top:110px;left:200px;width:610px;height:460px}

.notepad-tabbar{
  display:flex;align-items:stretch;background:#2f2f2f;
  border-bottom:1px solid rgba(0,0,0,0.3);
  flex-shrink:0;overflow:hidden;min-height:36px
}
#tabs{
  display:flex;flex:1;overflow-x:auto;gap:2px;padding:4px 4px 0;
  align-items:flex-end
}
#tabs::-webkit-scrollbar{height:3px}
#tabs::-webkit-scrollbar-thumb{background:rgba(255,255,255,0.18);border-radius:2px}

.tab{
  padding:5px 12px;border-radius:7px 7px 0 0;
  background:rgba(255,255,255,0.05);color:#999;
  font-size:12px;cursor:pointer;white-space:nowrap;
  display:flex;align-items:center;gap:6px;
  border:1px solid rgba(255,255,255,0.05);border-bottom:none;
  transition:background 0.12s,color 0.12s;user-select:none;
  max-width:160px;min-width:80px;flex-shrink:0
}
.tab.active{background:#2d2d2d;color:#e8e8e8;border-color:rgba(255,255,255,0.09)}
.tab:hover:not(.active){background:rgba(255,255,255,0.1);color:#bbb}
.tab-name{overflow:hidden;text-overflow:ellipsis;flex:1}
.tab-x{
  width:15px;height:15px;border-radius:50%;border:none;
  background:transparent;color:#777;font-size:13px;
  cursor:pointer;display:flex;align-items:center;justify-content:center;
  padding:0;line-height:1;flex-shrink:0;transition:background 0.12s,color 0.12s
}
.tab-x:hover{background:rgba(255,70,70,0.3);color:#ff8080}

#new-tab{
  background:transparent;border:none;color:#888;font-size:20px;
  width:34px;cursor:pointer;display:flex;align-items:center;
  justify-content:center;flex-shrink:0;
  transition:background 0.12s,color 0.12s;border-radius:0;margin:0 2px
}
#new-tab:hover{background:rgba(255,255,255,0.08);color:#ddd}

#editor{
  flex:1;background:#1e1e1e;color:#d4d4d4;border:none;
  padding:14px 16px;font-family:'Consolas','Courier New',monospace;
  font-size:14px;line-height:1.55;resize:none;outline:none
}
#editor::placeholder{color:#555}

/* Desktop decorative icons */
.desk-icon{
  position:absolute;display:flex;flex-direction:column;align-items:center;
  padding:10px 8px;border-radius:10px;cursor:default;
  color:#fff;font-size:11px;text-align:center;width:76px;
  text-shadow:0 1px 4px rgba(0,0,0,0.9);user-select:none;
  transition:background 0.12s
}
.desk-icon:hover{background:rgba(255,255,255,0.1)}
.desk-icon-img{font-size:36px;margin-bottom:4px;line-height:1}
</style>
