  </div>
  <div class="desk-icon" style="top:140px;left:20px">
    <div class="desk-icon-img">💻</div>Computer
  </div>

  <!-- Taskbar / Dock -->
  <div id="taskbar">
    <button id="open-files" data-tip="Files">📁</button>
    <button id="open-notepad" data-tip="Notepad">📝</button>
    <button data-tip="Terminal" style="opacity:.5;cursor:default">🖥️</button>
    <button data-tip="Settings" style="opacity:.5;cursor:default">⚙️</button>
  </div>

