    <div class="notepad-tabbar">
      <div id="tabs"></div>
      <button id="new-tab" title="New Tab">+</button>
    </div>
    <textarea id="editor" placeholder="Start typing…"></textarea>
  </div>

</div>

<script>
// ─── Clock ───────────────────────────────────────────────────────────────────
(function tick(){
  const d=new Date();
  document.getElementById('clock').textContent=
    d.toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'});
  setTimeout(tick,1000);
})();

// ─── Window management ───────────────────────────────────────────────────────
let zTop=10;

function bringToFront(win){win.style.zIndex=++zTop}

function showWindow(win){
  win.classList.add('visible');
  bringToFront(win);
}
function hideWindow(win){
  win.classList.remove('visible');
  win.style.display='';   // class controls display
}

function makeDraggable(win,handle){
  let ox,oy,dragging=false;
  handle.addEventListener('mousedown',e=>{
    if(e.target.classList.contains('win-btn'))return;
    dragging=true;
    const r=win.getBoundingClientRect();
    ox=e.clientX-r.left; oy=e.clientY-r.top;
    bringToFront(win);
    e.preventDefault();
  });
  document.addEventListener('mousemove',e=>{
    if(!dragging)return;
    let nx=e.clientX-ox, ny=e.clientY-oy;
    const maxX=window.innerWidth-win.offsetWidth;
    const maxY=window.innerHeight-win.offsetHeight;
    win.style.left=Math.max(0,Math.min(nx,maxX))+'px';
    win.style.top=Math.max(28,Math.min(ny,maxY-58))+'px';
  });
  document.addEventListener('mouseup',()=>{dragging=false});
}

document.querySelectorAll('.window').forEach(win=>{
  const bar=win.querySelector('.win-titlebar');
  makeDraggable(win,bar);
  win.addEventListener('mousedown',()=>bringToFront(win));
  win.querySelector('.win-close').addEventListener('click',()=>hideWindow(win));
  win.querySelector('.win-minimize').addEventListener('click',()=>{}); // decorative
  win.querySelector('.win-maximize').addEventListener('click',()=>{}); // decorative
});

document.getElementById('open-files').addEventListener('click',()=>{
  showWindow(document.getElementById('files-window'));
});
document.getElementById('open-notepad').addEventListener('click',()=>{
  showWindow(document.getElementById('notepad-window'));
});

// ─── Filesystem ──────────────────────────────────────────────────────────────
const FS={
  '/':{d:true,c:['bin','etc','home','usr','var']},
  '/bin':{d:true,c:['bash','cat','chmod','cp','echo','grep','ls','mkdir','mv','rm','sh']},
  '/etc':{d:true,c:['apt','fstab','hostname','hosts','network','passwd','ssh']},
  '/etc/apt':{d:true,c:['preferences','sources.list','trusted.gpg']},
  '/etc/ssh':{d:true,c:['ssh_config','sshd_config']},
  '/etc/network':{d:true,c:['interfaces']},
  '/home':{d:true,c:['user']},
  '/home/user':{d:true,c:['.bashrc','.profile','.ssh','Documents','Downloads','Pictures']},
  '/home/user/.ssh':{d:true,c:['authorized_keys','config','id_rsa','id_rsa.pub','known_hosts']},
  '/home/user/Documents':{d:true,c:['budget.xlsx','notes.txt','projects','readme.md','resume.pdf']},
  '/home/user/Documents/projects':{d:true,c:['scripts','webapp']},
  '/home/user/Documents/projects/scripts':{d:true,c:['backup.sh','deploy.sh','sync.sh']},
  '/home/user/Documents/projects/webapp':{d:true,c:['app.js','index.html','style.css']},
  '/home/user/Downloads':{d:true,c:['archive.tar.gz','setup.sh','ubuntu-22.04.iso']},
  '/home/user/Pictures':{d:true,c:['screenshot.png','vacation','wallpaper.jpg']},
  '/home/user/Pictures/vacation':{d:true,c:['beach.jpg','hotel.jpg','panorama.jpg']},
  '/usr':{d:true,c:['bin','include','lib','local','share']},
  '/usr/bin':{d:true,c:['curl','gcc','git','make','nano','node','python3','vim','wget']},
  '/usr/include':{d:true,c:['stdio.h','stdlib.h','string.h']},
  '/usr/lib':{d:true,c:['python3','systemd','x86_64-linux-gnu']},
  '/usr/local':{d:true,c:['bin','lib','share']},
  '/usr/local/bin':{d:true,c:['code','npm','yarn']},
  '/usr/share':{d:true,c:['applications','doc','fonts','icons','man']},
  '/var':{d:true,c:['cache','lib','log','run','tmp']},
  '/var/cache':{d:true,c:['apt','fontconfig']},
  '/var/lib':{d:true,c:['apt','dpkg','systemd']},
  '/var/log':{d:true,c:['apt','auth.log','kern.log','syslog']},
  '/var/log/apt':{d:true,c:['history.log','term.log']},
  '/var/run':{d:true,c:['sshd.pid','systemd']},
  '/var/tmp':{d:true,c:[]}
};

function isDir(path){return !!(FS[path]&&FS[path].d)}

function iconFor(name,parentPath){
  const full=parentPath==='/'?'/'+name:parentPath+'/'+name;
  if(isDir(full)){
    const map={home:'🏠',Documents:'📂',Downloads:'⬇️',Pictures:'🖼️',
               bin:'⚙️',etc:'🔧',usr:'📦',var:'📊',log:'📋',
               lib:'🗄️',share:'📤',local:'🗂️',include:'📎',
               apt:'📦',ssh:'🔐',network:'🌐',cache:'💾',run:'⚡',tmp:'🗑️'};
    return map[name]||'📁';
  }
  const ext=(name.includes('.')?name.split('.').pop():'').toLowerCase();
  const map={
    sh:'⚙️',bash:'⚙️',py:'🐍',js:'🟨',ts:'🔷',
    html:'🌐',css:'🎨',json:'📋',xml:'📋',
    pdf:'📄',txt:'📝',md:'📝',
    png:'🖼️',jpg:'🖼️',jpeg:'🖼️',gif:'🖼️',svg:'🖼️',
    iso:'💿',gz:'🗜️',tar:'🗜️',zip:'🗜️',
    xlsx:'📊',csv:'📊',
    log:'📋',conf:'🔧',cfg:'🔧',
    h:'📎',c:'📝',
    rsa:'🔑',pub:'🔑',
    list:'📋'
  };
  return map[ext]||(name.startsWith('.')? '⚙️':'📄');
}

let curPath='/';

function navigate(path){
  if(!isDir(path))return;
  curPath=path;
  document.getElementById('files-path').textContent=path;
  renderFiles();
}

function renderFiles(){
  const el=document.getElementById('files-content');
  el.innerHTML='';
  const node=FS[curPath];
  if(!node)return;
  (node.c||[]).forEach(name=>{
    const full=curPath==='/'?'/'+name:curPath+'/'+name;
    const dir=isDir(full);
    const item=document.createElement('div');
    item.className='fs-item';
    item.dataset.path=full;
    item.dataset.dir=dir?'1':'0';

    const ic=document.createElement('div');
    ic.className='fs-icon';
    ic.textContent=iconFor(name,curPath);

    const lb=document.createElement('div');
    lb.className='fs-label';
    lb.textContent=name;

    item.appendChild(ic);
    item.appendChild(lb);

    item.addEventListener('click',e=>{
      document.querySelectorAll('#files-content .fs-item.selected')
        .forEach(x=>x.classList.remove('selected'));
      item.classList.add('selected');
    });

    let lastClick=0;
    item.addEventListener('click',()=>{
      const now=Date.now();
      if(now-lastClick<400&&dir)navigate(full);
      lastClick=now;
    });
    // Native dblclick also navigates
    item.addEventListener('dblclick',()=>{if(dir)navigate(full)});

    el.appendChild(item);
  });
}

document.getElementById('files-up').addEventListener('click',()=>{
  if(curPath==='/')return;
  const parts=curPath.split('/').filter(Boolean);
  parts.pop();
  navigate(parts.length===0?'/':`/${parts.join('/')}`);
});

navigate('/');

// ─── Notepad (with localStorage) ─────────────────────────────────────────────
const LS_TABS='dt_notepad_tabs';
const LS_ACT='dt_notepad_active';

function loadTabs(){
  try{
    const raw=localStorage.getItem(LS_TABS);
    if(raw){const t=JSON.parse(raw);if(Array.isArray(t)&&t.length)return t;}
  }catch(_){}
  return [{id:1,title:'Untitled 1',content:''}];
}
function loadActive(tabs){
  try{
    const id=parseInt(localStorage.getItem(LS_ACT));
    if(tabs.find(t=>t.id===id))return id;
  }catch(_){}
  return tabs[0].id;
}

let tabs=loadTabs();
let activeId=loadActive(tabs);
let nextId=Math.max(...tabs.map(t=>t.id))+1;

function saveTabs(){
  try{
    localStorage.setItem(LS_TABS,JSON.stringify(tabs));
    localStorage.setItem(LS_ACT,String(activeId));
  }catch(_){}
}

function renderTabs(){
  const strip=document.getElementById('tabs');
  strip.innerHTML='';
  tabs.forEach(tab=>{
    const el=document.createElement('div');
    el.className='tab'+(tab.id===activeId?' active':'');
    el.dataset.id=tab.id;

    const nm=document.createElement('span');
    nm.className='tab-name';
    nm.textContent=tab.title;

    const x=document.createElement('button');
    x.className='tab-x';
    x.textContent='×';
    x.title='Close';

    el.appendChild(nm);
    el.appendChild(x);

    el.addEventListener('click',e=>{
      if(e.target===x)return;
      flushEditor();
      activeId=tab.id;
      saveTabs();
      renderTabs();
      document.getElementById('editor').value=tabs.find(t=>t.id===activeId)?.content||'';
    });
    x.addEventListener('click',e=>{
      e.stopPropagation();
      removeTab(tab.id);
    });

    strip.appendChild(el);
  });
  // scroll active into view
  const activeEl=strip.querySelector('.tab.active');
  if(activeEl)activeEl.scrollIntoView({inline:'nearest',block:'nearest'});
}

function flushEditor(){
  const t=tabs.find(t=>t.id===activeId);
  if(t)t.content=document.getElementById('editor').value;
}

function removeTab(id){
  flushEditor();
  if(tabs.length<=1){
    // Reset single tab
    tabs[0].content='';
    tabs[0].title='Untitled 1';
    activeId=tabs[0].id;
    saveTabs();
    renderTabs();
    document.getElementById('editor').value='';
    return;
  }
  const idx=tabs.findIndex(t=>t.id===id);
  tabs.splice(idx,1);
  if(activeId===id){
    activeId=tabs[Math.min(idx,tabs.length-1)].id;
  }
  saveTabs();
  renderTabs();
  document.getElementById('editor').value=tabs.find(t=>t.id===activeId)?.content||'';
}

document.getElementById('new-tab').addEventListener('click',()=>{
  flushEditor();
  const id=nextId++;
  const num=tabs.length+1;
  tabs.push({id,title:`Untitled ${num}`,content:''});
  activeId=id;
  saveTabs();
  renderTabs();
  const ed=document.getElementById('editor');
  ed.value='';
  ed.focus();
});

document.getElementById('editor').addEventListener('input',()=>{
  const t=tabs.find(t=>t.id===activeId);
  if(!t)return;
  t.content=document.getElementById('editor').value;
  // derive title from first line
  const first=t.content.split('\n')[0].trim();
  const tabIdx=tabs.indexOf(t);
  t.title=first?first.slice(0,22)+(first.length>22?'…':''):`Untitled ${tabIdx+1}`;
  saveTabs();
  // update tab label without full re-render
  const nm=document.querySelector(`#tabs .tab[data-id="${activeId}"] .tab-name`);
  if(nm)nm.textContent=t.title;
});

// Initial render
renderTabs();
document.getElementById('editor').value=tabs.find(t=>t.id===activeId)?.content||'';
</script>
</body>
